      "content": "const _ = require('lodash');
const problemsData = require('../../data/problems.json');

class ProblemsService {
  /**
   * List problems with optional filters and metadata including component language and status totals.
   * @param {Object} params
   * @param {boolean} params.includeComponents - Whether to include component metadata counts.
   * @param {number} [params.limit] - Limit the number of problems returned.
   * @param {string[]} [params.tags] - Filter problems by tags.
   * @param {string[]} [params.difficulties] - Filter problems by difficulty.
   * @returns {Object} result with problems array and optional metadata
   */
  static listProblems({ includeComponents = false, limit, tags, difficulties } = {}) {
    // Start with all problems
    let filteredProblems = problemsData;

    // Filter by tags if provided
    if (tags && tags.length > 0) {
      filteredProblems = filteredProblems.filter(problem => {
        if (!problem.tags) return false;
        return tags.every(tag => problem.tags.includes(tag));
      });
    }

    // Filter by difficulties if provided
    if (difficulties && difficulties.length > 0) {
      filteredProblems = filteredProblems.filter(problem => difficulties.includes(problem.difficulty));
    }

    // Apply limit if provided
    if (typeof limit === 'number' && limit >= 0) {
      filteredProblems = filteredProblems.slice(0, limit);
    }

    const result = {
      problems: filteredProblems
    };

    if (includeComponents) {
      // Compute componentLanguageTotals and componentStatusTotals for filtered + limited problems
      const componentLanguageTotals = {};
      const componentStatusTotals = {};

      filteredProblems.forEach(problem => {
        if (problem.components && Array.isArray(problem.components)) {
          problem.components.forEach(component => {
            // Count by language
            if (component.language) {
              componentLanguageTotals[component.language] = (componentLanguageTotals[component.language] || 0) + 1;
            }
            // Count by status
            if (component.status) {
              componentStatusTotals[component.status] = (componentStatusTotals[component.status] || 0) + 1;
            }
          });
        }
      });

      result.metadata = {
        componentLanguageTotals,
        componentStatusTotals
      };
    }

    return result;
  }
}

module.exports = ProblemsService;
